// =============================================================
// Prepare Current Step — resolve variables in config
// =============================================================
// Uses execution-scoped state keyed by executionId to support
// concurrent workflow executions. Initializes on stepIndex 0.
// =============================================================

const Sentry = require('@sentry/node');

// @inline resolve-variables
function resolveVariables(template, context) {
  if (typeof template !== 'string') return template;
  return template.replace(/\{\{(\s*[\w.]+\s*)\}\}/g, (_, rawKey) => {
    const key = rawKey.trim();
    const value = getNestedValue(context, key);
    return (value !== undefined && value !== null) ? String(value) : `{{${key}}}`;
  });
}
// @end-inline resolve-variables

// @inline get-nested-value
function getNestedValue(obj, path) {
  const parts = path.split('.');
  let current = obj;
  for (const part of parts) {
    if (current === null || current === undefined || typeof current !== 'object') return undefined;
    current = current[part];
  }
  return current;
}
// @end-inline get-nested-value
function resolveDeep(obj, context) {
  if (typeof obj === 'string') return resolveVariables(obj, context);
  if (Array.isArray(obj)) return obj.map(item => resolveDeep(item, context));
  if (obj && typeof obj === 'object') {
    const result = {};
    for (const [key, value] of Object.entries(obj)) {
      result[key] = resolveDeep(value, context);
    }
    return result;
  }
  return obj;
}

try {
  const item = $input.first().json;
  const state = $getWorkflowStaticData('global');
  const { currentStep, executionId } = item;

  // Initialize execution-scoped state on first step
  if (item.stepIndex === 0) {
    // Clean up stale entries older than 2 hours (defensive)
    for (const key of Object.keys(state)) {
      const entry = state[key];
      if (entry && entry._createdAt && (Date.now() - entry._createdAt > 7200000)) {
        delete state[key];
      }
    }
    state[executionId] = {
      variableContext: item.initialVariableContext || {},
      skippedStepIds: [],
      failed: false,
      failureError: null,
      _createdAt: Date.now(),
    };
  }

  const execState = state[executionId] || { variableContext: {}, skippedStepIds: [], failed: false };

  if (execState.failed) {
    return { json: { ...item, failed: true } };
  }

  if ((execState.skippedStepIds || []).includes(currentStep.id)) {
    Sentry.addBreadcrumb({
      message: `Step ${item.stepIndex + 1}/${item.totalSteps}: ${currentStep.step_type} (${currentStep.id}) SKIPPED by condition branch`,
      level: 'info',
    });
    return {
      json: {
        ...item,
        resolvedConfig: currentStep.step_config,
        stepType: '__skipped__',
        stepResult: { success: true, outputPayload: { skipped: true } },
        alreadyPersisted: true,
      }
    };
  }

  const variableContext = execState.variableContext || {};
  const resolvedConfig = resolveDeep(currentStep.step_config, variableContext);

  Sentry.addBreadcrumb({
    message: `Step ${item.stepIndex + 1}/${item.totalSteps}: ${currentStep.step_type} (${currentStep.name || currentStep.id})`,
    level: 'info',
  });

  return {
    json: {
      ...item,
      variableContext,
      resolvedConfig,
      stepType: currentStep.step_type,
    }
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// Mark current step as running. PATCH then propagate item downstream so
// Route by Step Type sees the same pipeline state. Replays bypass via
// Should Mark Running [false] branch directly to Route by Step Type.
const item = $input.first().json;
if (!item.currentStepExecId) return { json: item };

// @inline env-supabase-preamble
const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
if (!SUPABASE_URL) throw new Error('SUPABASE_URL environment variable not configured');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
// @end-inline env-supabase-preamble

// @inline supabase-request
async function supabaseRequest(path, method, body, opts) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const match = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!match) { reject(new Error('Invalid SUPABASE_URL')); return; }
    const prefer = (opts && opts.prefer) || 'return=representation';
    const options = {
      hostname: match[1],
      path: match[2],
      method: method || 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': prefer,
      },
    };
    const req = https.request(options, (res) => {
      // UTF-8 boundary safety: without setEncoding, chunks are Buffers and
      // `data += chunk` does an implicit chunk.toString() PER chunk. When a
      // multi-byte UTF-8 character (e.g. 'ł' = 0xC5 0x82) straddles a chunk
      // boundary, each half decodes to U+FFFD (replacement char). setEncoding
      // makes Node buffer internally and emit string chunks only at character
      // boundaries — concat-safe for any UTF-8 payload.
      res.setEncoding('utf8');
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase ${method || 'GET'} ${path} ${res.statusCode}: ${data}`));
          return;
        }
        try {
          resolve(data ? JSON.parse(data) : null);
        } catch (e) {
          reject(new Error(`Parse error for ${path}: ${data}`));
        }
      });
    });
    req.on('error', reject);
    if (body !== undefined && body !== null) req.write(JSON.stringify(body));
    req.end();
  });
}
// @end-inline supabase-request

await supabaseRequest(
  `workflow_step_executions?id=eq.${item.currentStepExecId}`,
  'PATCH',
  { status: 'running', started_at: new Date().toISOString() }
);

return { json: item };

// Unknown step type handler
const item = $input.first().json;
return {
  json: {
    ...item,
    stepResult: {
      success: false,
      error: `Unknown step type: ${item.stepType}`,
    },
  }
};

// =============================================================
// Process Step Result — merge context, handle failure/skipping
// =============================================================
// Uses execution-scoped state keyed by executionId.
// Cleans up state entry on last step.
// =============================================================

const Sentry = require('@sentry/node');

try {
  const item = $input.first().json;
  const state = $getWorkflowStaticData('global');
  const { currentStep, executionId } = item;
  const execState = state[executionId] || { variableContext: {}, skippedStepIds: [], failed: false };

  // If already in failed passthrough mode, just return
  if (item.failed || execState.failed) {
    if (item.stepIndex === item.totalSteps - 1) delete state[executionId];
    return { json: item };
  }

  // Get step result from subworkflow output
  let stepResult = item.stepResult;
  if (!stepResult) {
    stepResult = { success: false, error: 'No step result produced' };
  }

  // Namespace step output by step number (1-based topological order) for human-readable templates.
  // Trigger variables stay flat. Step outputs keyed by step.slug (not positional).
  // Slug is per-workflow unique, user-editable, persisted on workflow_steps row.
  // Template syntax: {{slug.fieldName}} — same key on both CMS and runtime sides.
  if (stepResult.success && stepResult.outputPayload) {
    const stepKey = currentStep.slug;
    if (!stepKey) {
      throw new Error(`Step ${currentStep.id} has no slug — required for variableContext keying`);
    }
    execState.variableContext[stepKey] = stepResult.outputPayload;
  }

  // Accumulate skipped step IDs from condition branching
  const newSkipped = item.skippedStepIds || [];
  if (newSkipped.length > 0) {
    execState.skippedStepIds = [...(execState.skippedStepIds || []), ...newSkipped];
  }

  // Write back to state
  state[executionId] = execState;

  // Prepare DB update fields
  const now = new Date().toISOString();
  const alreadyPersisted = item.alreadyPersisted || stepResult.alreadyPersisted || false;
  const isLastStep = item.stepIndex === item.totalSteps - 1;

  // If step failed: signal to skip remaining steps
  if (!stepResult.success) {
    execState.failed = true;
    execState.failureError = stepResult.error;
    state[executionId] = execState;

    Sentry.captureException(new Error(`Step failed: ${currentStep.step_type} — ${stepResult.error}`));
    await Sentry.flush(2000);

    if (isLastStep) delete state[executionId];

    return {
      json: {
        ...item,
        variableContext: execState.variableContext,
        failed: true,
        failureError: stepResult.error,
        dbStatus: 'failed',
        dbCompletedAt: now,
        dbErrorMessage: stepResult.error || 'Unknown error',
        dbOutputPayload: null,
        alreadyPersisted,
        skippedStepIds: newSkipped,
      }
    };
  }

  if (isLastStep) delete state[executionId];

  return {
    json: {
      ...item,
      variableContext: execState.variableContext,
      stepResult: null,
      dbStatus: 'completed',
      dbCompletedAt: now,
      dbOutputPayload: stepResult.outputPayload || {},
      dbErrorMessage: null,
      alreadyPersisted,
      skippedStepIds: newSkipped,
    }
  };

} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// Failed passthrough — emit dbStatus='cancelled' so Update Step Execution
// patches the row (T-208 fix: previously emitted bare item → row stuck running).
// alreadyPersisted=false ensures Persist Gate routes to Update Step Execution.
const item = $input.first().json;
return {
  json: {
    ...item,
    dbStatus: 'cancelled',
    dbCompletedAt: new Date().toISOString(),
    dbErrorMessage: 'Anulowano — wcześniejszy krok zakończył się błędem',
    dbOutputPayload: null,
    alreadyPersisted: false,
  },
};

