    Object.assign(state[executionId].variableContext, row.output_payload || {});
  } else if (row.status === 'skipped') {
    if (!state[executionId].skippedStepIds.includes(stepId)) {
      state[executionId].skippedStepIds.push(stepId);
    }
  }
