// =============================================================
// Decide Replay Action — pure branch decision (no DB writes)
// =============================================================
// Sets `replayAction` field marker on item. Side-effect (INSERT
// for new attempts) extracted to next node Insert New Attempt.
//   completed → reuse_completed (emit __replay__ + cached output)
//   skipped   → reuse_skipped (emit __replay_skipped__)
//   failed/pending/running (other than current) → new_attempt
//     (Insert New Attempt node performs the INSERT)
//   waiting/processing/cancelled / no prev → continue
// Always strips _prevAttempt before forwarding (internal-only field).
// =============================================================

const item = $input.first().json;

// Passthrough — no replay logic for failed/skipped paths.
// Strip _prevAttempt defensively (Find Latest Attempt skips it for these,
// but be safe in case future changes attach it earlier).
if (item.failed) {
  const { _prevAttempt: _ignored1, ...rest } = item;
  return { json: rest };
}
if (item.stepType === '__skipped__') {
  const { _prevAttempt: _ignored2, ...rest } = item;
  return { json: rest };
}

const { _prevAttempt: prev, ...itemBase } = item;

if (!prev) {
  // First execution — no prior attempt. Continue with existing currentStepExecId.
  return { json: { ...itemBase, replayAction: 'continue' } };
}

if (prev.status === 'completed') {
  // Reuse cached output via __replay__ stepType
  return {
    json: {
      ...itemBase,
      replayAction: 'reuse_completed',
      stepType: '__replay__',
      stepResult: {
        success: true,
        outputPayload: prev.output_payload || {},
        alreadyPersisted: true,
      },
      alreadyPersisted: true,
    },
  };
}

if (prev.status === 'skipped') {
  // Step was skipped in prior attempt — preserve skip via __replay_skipped__
  return {
    json: {
      ...itemBase,
      replayAction: 'reuse_skipped',
      stepType: '__replay_skipped__',
      stepResult: {
        success: true,
        outputPayload: {},
        alreadyPersisted: true,
      },
      alreadyPersisted: true,
    },
  };
}

if (prev.status === 'failed' || prev.status === 'pending' || prev.status === 'running') {
  // Guard: ONLY for pending status (first-execution detection).
  // On first execution, Orchestrator pre-inserts a 'pending' row and sets currentStepExecId to it.
  // Find Latest Attempt then returns this same pending row — guard fires → 'continue' (correct).
  // On RETRY, Orchestrator reuses the existing latest-attempt row's ID as currentStepExecId.
  // The 'failed' / 'running' row matches ID too — but the old guard (no status check) incorrectly
  // routed to 'continue', suppressing the new_attempt INSERT. Fix: require status === 'pending'.
  if (prev.status === 'pending' && prev.id === itemBase.currentStepExecId) {
    return { json: { ...itemBase, replayAction: 'continue' } };
  }

  // Real retry path: stuck failed/pending row from prior crashed execution.
  // Mark for INSERT in next node; preserve attempt number for the INSERT.
  return {
    json: {
      ...itemBase,
      replayAction: 'new_attempt',
      _newAttemptNumber: (prev.attempt_number || 1) + 1,
    },
  };
}

