  // If reused, Mark Step Running would overwrite status='running', losing the
  // audit trail. Create a new attempt (attempt_number + 1) instead.
  return {
    json: {
      ...itemBase,
      replayAction: 'new_attempt',
      _newAttemptNumber: (prev.attempt_number || 1) + 1,
    },
  };
